#[serde(rename_all = "snake_case")]
enum BackgroundJobEventPhase {
    Started,
    CancelRequested,
    Completed,
    Failed,
    Retried,
    IgnoredStale,
}

impl BackgroundJobEventPhase {
    fn label(self) -> &'static str {
        match self {
            Self::Started => "started",
            Self::CancelRequested => "cancel-requested",
            Self::Completed => "completed",
            Self::Failed => "failed",
            Self::Retried => "retried",
            Self::IgnoredStale => "ignored-stale",
        }
    }
}

#[derive(Clone, Debug, Serialize, Deserialize)]
struct BackgroundJobEvent {
    job_id: Option<u64>,
    kind: BackgroundJobKind,
    phase: BackgroundJobEventPhase,
    emitted_at_unix_ms: u128,
    summary: String,
}

impl BackgroundJobEvent {
    fn to_line(&self) -> String {
        let job_token = self
            .job_id
            .map(|id| format!("#{id}"))
            .unwrap_or_else(|| "#-".to_string());
        format!(
            "[{} {} {} @{}] {}",
            self.kind.label(),
            job_token,
            self.phase.label(),
            self.emitted_at_unix_ms,
            self.summary
        )
    }
}

#[derive(Clone, Debug, Serialize, Deserialize)]
#[serde(default)]
struct BackgroundJobRetrySnapshot {
    snapshot_id: u64,
    kind: BackgroundJobKind,
    origin: String,
    captured_at_unix_ms: u128,
    arguments: serde_json::Value,
}

impl Default for BackgroundJobRetrySnapshot {
    fn default() -> Self {
        Self {
            snapshot_id: 0,
            kind: BackgroundJobKind::PrepareGenome,
            origin: String::new(),
            captured_at_unix_ms: 0,
            arguments: serde_json::Value::Null,
        }
    }
}

impl BackgroundJobRetrySnapshot {
    fn to_line(&self) -> String {
        let args = serde_json::to_string(&self.arguments)
            .unwrap_or_else(|_| "{\"error\":\"could not format retry args\"}".to_string());
        let mut compact = args.replace('\n', " ");
        if compact.len() > 220 {
            compact.truncate(220);
            compact.push_str("...");
        }
        format!(
            "[{} retry#{} @{} from {}] {}",
            self.kind.label(),
            self.snapshot_id,
            self.captured_at_unix_ms,
            if self.origin.trim().is_empty() {
                "-"
            } else {
                self.origin.trim()
            },
            compact
        )
    }
}

#[derive(Clone, Debug, Serialize, Deserialize)]
#[serde(default)]
struct RetrySnapshotCleanupAuditEntry {
    audit_id: u64,
    action: String,
    performed_at_unix_ms: u128,
    target_count: usize,
    removed_count: usize,
    retained_before: usize,
    retained_after: usize,
    filter_kind: String,
    filter_text: String,
    archive_path: Option<String>,
    summary: String,
}

impl Default for RetrySnapshotCleanupAuditEntry {
    fn default() -> Self {
        Self {
            audit_id: 0,
            action: String::new(),
            performed_at_unix_ms: 0,
            target_count: 0,
            removed_count: 0,
            retained_before: 0,
            retained_after: 0,
            filter_kind: String::new(),
            filter_text: String::new(),
            archive_path: None,
            summary: String::new(),
        }
    }
}

impl RetrySnapshotCleanupAuditEntry {
    fn to_line(&self) -> String {
        let mut summary = self.summary.replace('\n', " ");
        if summary.len() > 180 {
            summary.truncate(180);
            summary.push_str("...");
        }
        let filter_text = if self.filter_text.trim().is_empty() {
            "-".to_string()
        } else {
            self.filter_text.trim().to_string()
        };
        let archive_token = self
            .archive_path
            .as_deref()
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .unwrap_or("-");
        format!(
            "[audit#{} {} @{} removed={} retained {}->{} target={} filter(kind={}, text={}) archive={}] {}",
            self.audit_id,
            self.action,
            self.performed_at_unix_ms,
            self.removed_count,
            self.retained_before,
            self.retained_after,
            self.target_count,
            self.filter_kind,
            filter_text,
            archive_token,
            summary
        )
    }
}

